scripts.build:extension:bundle:
mkdir -p build/extension && esbuild src/extension.ts --bundle --outfile=build/extension/extension.js --platform=neutral --target=es2020 --global-name=DynamicTiler --format=iife && printf '
var init = DynamicTiler.init;
var enable = DynamicTiler.enable;
var disable = DynamicTiler.disable;
' >> build/extension/extension.js && cp settings-schema.json metadata.json build/extension/
